// components/ChatbotInterface.jsx - UPDATED
import React, { useState, useRef, useEffect } from 'react';
import axios from 'axios';
import './ERPChatBot.css';

const ChatbotInterface = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState([]);
  const [inputMessage, setInputMessage] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [sessionId, setSessionId] = useState(null);
  const [userInfo, setUserInfo] = useState(null);
  const [authChecked, setAuthChecked] = useState(false);
  const messagesEndRef = useRef(null);
  const inputRef = useRef(null);

  // Check authentication and get user info
  useEffect(() => {
    checkAuth();
    
    // Load previous messages
    const savedMessages = localStorage.getItem('chatbot_messages');
    if (savedMessages) {
      setMessages(JSON.parse(savedMessages));
    }
  }, []);

  // Auto-scroll to bottom
  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  // Save messages to localStorage
  useEffect(() => {
    if (messages.length > 0) {
      localStorage.setItem('chatbot_messages', JSON.stringify(messages));
    }
  }, [messages]);

  const checkAuth = async () => {
    try {
      const response = await axios.get('/api/auth/me', {
        withCredentials: true
      });
      
      if (response.data.user) {
        setUserInfo(response.data.user);
        
        // Store studentId in localStorage for easy access
        if (response.data.user.studentId) {
          localStorage.setItem('studentId', response.data.user.studentId);
          localStorage.setItem('userRole', response.data.user.role);
        }
      }
      setAuthChecked(true);
    } catch (error) {
      console.log('Not logged in or session expired');
      setUserInfo(null);
      setAuthChecked(true);
    }
  };

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  const handleSendMessage = async (e) => {
    e.preventDefault();
    
    // Check authentication
    if (!userInfo) {
      addSystemMessage("Please log in to use the chatbot.");
      setIsOpen(true);
      return;
    }
    
    if (!inputMessage.trim() || isLoading) return;

    const userMessage = inputMessage.trim();
    setInputMessage('');
    
    // Add user message to chat
    const newUserMessage = {
      id: Date.now(),
      text: userMessage,
      sender: 'user',
      timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
    };
    
    setMessages(prev => [...prev, newUserMessage]);
    setIsLoading(true);

    try {
      // ✅ FIXED: Don't send studentId, just message and sessionId
      // Session cookie will handle authentication
      const response = await axios.post('/api/chatbot/chat', {
        message: userMessage,
        sessionId: sessionId
      }, {
        withCredentials: true  // IMPORTANT: Send session cookie
      });

      if (response.data.success) {
        // Set session ID if this is the first response
        if (!sessionId && response.data.sessionId) {
          setSessionId(response.data.sessionId);
        }

        // Add bot response to chat
        const botMessage = {
          id: Date.now() + 1,
          text: response.data.response,
          sender: 'bot',
          timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
          metadata: response.data.metadata
        };
        
        setMessages(prev => [...prev, botMessage]);
      } else {
        // Error handling
        const errorMessage = {
          id: Date.now() + 1,
          text: response.data.message || "I'm having trouble connecting right now.",
          sender: 'bot',
          timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
          isError: true
        };
        
        setMessages(prev => [...prev, errorMessage]);
      }
    } catch (error) {
      console.error('Chat error:', error);
      
      let errorText = "Sorry, I'm having trouble connecting. Please check your internet connection.";
      
      if (error.response?.status === 401) {
        errorText = "Please log in again to use the chatbot.";
      } else if (error.response?.status === 400) {
        errorText = error.response.data.message || "Invalid request.";
      }
      
      const errorMessage = {
        id: Date.now() + 1,
        text: errorText,
        sender: 'bot',
        timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
        isError: true
      };
      
      setMessages(prev => [...prev, errorMessage]);
    } finally {
      setIsLoading(false);
      setTimeout(() => inputRef.current?.focus(), 100);
    }
  };

  const addSystemMessage = (text) => {
    const systemMessage = {
      id: Date.now(),
      text: text,
      sender: 'system',
      timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
    };
    setMessages(prev => [...prev, systemMessage]);
  };

  const handleKeyPress = (e) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage(e);
    }
  };

  const handleClearChat = () => {
    if (window.confirm('Clear all chat history?')) {
      setMessages([]);
      localStorage.removeItem('chatbot_messages');
      setSessionId(null);
    }
  };

  const handleQuickAction = (text) => {
    setInputMessage(text);
    setTimeout(() => {
      if (inputRef.current) {
        inputRef.current.focus();
      }
    }, 100);
  };

  const quickActions = [
    { text: "What's my fee due?", icon: "💰" },
    { text: "Show today's timetable", icon: "📅" },
    { text: "My attendance in CS101", icon: "📊" },
    { text: "Upcoming events", icon: "🎉" },
    { text: "Show my results", icon: "📝" },
    { text: "What courses do I have?", icon: "📚" }
  ];

  // Show loading while checking auth
  if (!authChecked) {
    return (
      <div className="chatbot-loading">
        <div className="spinner"></div>
      </div>
    );
  }

  return (
    <>
      {/* Chatbot Icon (Bottom Left) */}
      {!isOpen && (
        <button 
          className="chatbot-icon"
          onClick={() => {
            if (!userInfo) {
              addSystemMessage("Please log in to use the chatbot.");
            }
            setIsOpen(true);
          }}
          aria-label="Open chatbot"
          title={userInfo ? `Logged in as ${userInfo.studentId || userInfo.email}` : "Please log in"}
        >
          <div className="chatbot-icon-inner">
            <svg width="24" height="24" viewBox="0 0 24 24" fill="none">
              <path d="M12 2C6.48 2 2 6.48 2 12C2 17.52 6.48 22 12 22C17.52 22 22 17.52 22 12C22 6.48 17.52 2 12 2ZM12 20C7.59 20 4 16.41 4 12C4 7.59 7.59 4 12 4C16.41 4 20 7.59 20 12C20 16.41 16.41 20 12 20Z" fill="white"/>
              <path d="M11 11H13V17H11V11ZM11 7H13V9H11V7Z" fill="white"/>
            </svg>
            <span className="chatbot-icon-badge">
              {userInfo ? "💬" : "🔒"}
            </span>
          </div>
          {!userInfo && (
            <div className="chatbot-icon-tooltip">Login Required</div>
          )}
        </button>
      )}

      {/* Chatbot Window */}
      {isOpen && (
        <div className="chatbot-window">
          {/* Header */}
          <div className="chatbot-header">
            <div className="chatbot-header-content">
              <div className="chatbot-avatar">
                <span>🤖</span>
              </div>
              <div className="chatbot-header-text">
                <h3>ERP Assistant</h3>
                <p className="chatbot-status">
                  {isLoading ? 'Typing...' : userInfo ? 'Online' : 'Please Login'}
                  {userInfo?.studentId && (
                    <span className="chatbot-user-id"> • {userInfo.studentId}</span>
                  )}
                </p>
              </div>
            </div>
            <button 
              className="chatbot-close-btn"
              onClick={() => setIsOpen(false)}
              aria-label="Close chatbot"
            >
              <svg width="20" height="20" viewBox="0 0 24 24" fill="none">
                <path d="M19 6.41L17.59 5L12 10.59L6.41 5L5 6.41L10.59 12L5 17.59L6.41 19L12 13.41L17.59 19L19 17.59L13.41 12L19 6.41Z" fill="currentColor"/>
              </svg>
            </button>
          </div>

          {/* Messages Container */}
          <div className="chatbot-messages">
            {messages.length === 0 ? (
              <div className="chatbot-welcome">
                <div className="welcome-avatar">
                  <span>🤖</span>
                </div>
                <h3>Hello{userInfo?.firstName ? ` ${userInfo.firstName}` : ''}!</h3>
                <p>I'm your ERP Assistant. I can help you with:</p>
                
                <div className="quick-actions">
                  <div className="quick-actions-grid">
                    {quickActions.map((action, index) => (
                      <button
                        key={index}
                        className="quick-action-btn"
                        onClick={() => handleQuickAction(action.text)}
                        disabled={!userInfo}
                        title={!userInfo ? "Please login first" : ""}
                      >
                        <span className="quick-action-icon">{action.icon}</span>
                        <span className="quick-action-text">{action.text}</span>
                      </button>
                    ))}
                  </div>
                  
                  {!userInfo && (
                    <div className="login-prompt">
                      <p>⚠️ Please log in to ask questions about your data.</p>
                      <button 
                        className="login-btn"
                        onClick={() => window.location.href = '/login'}
                      >
                        Go to Login
                      </button>
                    </div>
                  )}
                </div>
              </div>
            ) : (
              messages.map((message) => (
                <div
                  key={message.id}
                  className={`message ${message.sender} ${message.isError ? 'error' : ''}`}
                >
                  {message.sender === 'bot' && (
                    <div className="message-avatar">🤖</div>
                  )}
                  {message.sender === 'system' && (
                    <div className="message-avatar">ℹ️</div>
                  )}
                  <div className="message-content">
                    <div className="message-text">
                      {message.text.split('\n').map((line, i) => (
                        <React.Fragment key={i}>
                          {line}
                          {i < message.text.split('\n').length - 1 && <br />}
                        </React.Fragment>
                      ))}
                    </div>
                    <div className="message-timestamp">
                      {message.timestamp}
                      {message.metadata?.intent && (
                        <span className="message-intent">
                          • {message.metadata.intent}
                        </span>
                      )}
                    </div>
                  </div>
                  {message.sender === 'user' && (
                    <div className="message-avatar user-avatar">👤</div>
                  )}
                </div>
              ))
            )}
            
            {isLoading && (
              <div className="message bot">
                <div className="message-avatar">🤖</div>
                <div className="message-content">
                  <div className="typing-indicator">
                    <span></span>
                    <span></span>
                    <span></span>
                  </div>
                </div>
              </div>
            )}
            
            <div ref={messagesEndRef} />
          </div>

          {/* Input Area */}
          <form className="chatbot-input-area" onSubmit={handleSendMessage}>
            <div className="input-wrapper">
              <textarea
                ref={inputRef}
                value={inputMessage}
                onChange={(e) => setInputMessage(e.target.value)}
                onKeyPress={handleKeyPress}
                placeholder={userInfo ? "Ask about fees, attendance, timetable..." : "Please log in to ask questions"}
                rows="1"
                disabled={isLoading || !userInfo}
                autoFocus={userInfo}
              />
              <button 
                type="submit" 
                className="send-btn"
                disabled={!inputMessage.trim() || isLoading || !userInfo}
                title={!userInfo ? "Please login first" : ""}
              >
                {isLoading ? (
                  <div className="spinner"></div>
                ) : (
                  <svg width="20" height="20" viewBox="0 0 24 24" fill="none">
                    <path d="M2.01 21L23 12L2.01 3L2 10L17 12L2 14L2.01 21Z" fill="currentColor"/>
                  </svg>
                )}
              </button>
            </div>
            
            <div className="chatbot-footer">
              <button 
                type="button" 
                className="footer-btn"
                onClick={handleClearChat}
                title="Clear chat history"
              >
                <svg width="16" height="16" viewBox="0 0 24 24" fill="none">
                  <path d="M19 6.41L17.59 5L12 10.59L6.41 5L5 6.41L10.59 12L5 17.59L6.41 19L12 13.41L17.59 19L19 17.59L13.41 12L19 6.41Z" fill="currentColor"/>
                </svg>
                Clear
              </button>
              
              <div className="user-info">
                {userInfo ? (
                  <>
                    <span className="user-role">{userInfo.role}</span>
                    {userInfo.studentId && (
                      <span className="user-id">{userInfo.studentId}</span>
                    )}
                  </>
                ) : (
                  <span className="user-not-logged">Not logged in</span>
                )}
              </div>
              
              <div className="hint-text">
                {userInfo ? "Press Enter to send • Shift+Enter for new line" : "Login required"}
              </div>
            </div>
          </form>
        </div>
      )}
    </>
  );
};

export default ChatbotInterface;
